-- ترجمة البيانات: تحديث name_en و description_en للجداول (pages, services, specializations, clients) حيث name_en فارغ
UPDATE pages SET name_en = COALESCE((SELECT translation FROM (VALUES ('استراتيجية التسويق','Marketing Strategy'),('صناعة المحتوى','Content Creation'),('تصوير الفيديو','Video Production'),('الإنتاج الإعلامي','Media Production'),('بناء الهوية التجارية','Brand Identity'),('تصميم المواقع','Website Design'),('حملات السوشيال ميديا','Social Media Campaigns'),('تصميم المنشورات','Post Design'),('التصوير الفوتوغرافي','Photography')) AS t(ar,en) WHERE name = ar), name_en), description_en = COALESCE((SELECT en FROM (VALUES ('صياغة استراتيجيات تسويقية متكاملة توجه قرارات النمو وتمنح مشروعك مسارًا واضحًا وقابلًا للتنفيذ.','Formulating integrated marketing strategies that guide growth decisions and give your project a clear and executable path.'),('إنتاج محتوى يعبّر عن هويتك ويخاطب جمهورك بالشكل المناسب لكل منصة ومرحلة من رحلة العميل.','Producing content that expresses your identity and addresses your audience appropriately for each platform and stage of the customer journey.'),('تنفيذ فيديوهات احترافية للإعلانات والمحتوى الترويجي والرسائل البصرية التي تعكس قيمة مشروعك.','Executing professional videos for advertisements, promotional content, and visual messages that reflect your project value.'),('خدمات إنتاج متكاملة تشمل التخطيط والتنفيذ وما بعد الإنتاج لتقديم مخرجات جاهزة للنشر والتوزيع.','Integrated production services including planning, execution, and post-production to deliver outputs ready for publishing and distribution.'),('تصميم هوية بصرية متماسكة تمنح علامتك شخصية واضحة وتترك انطباعًا احترافيًا ومستدامًا.','Designing a cohesive visual identity that gives your brand a clear personality and leaves a professional and sustainable impression.'),('تصميم وتطوير مواقع حديثة وسريعة ومقنعة تساعد على تحويل الزيارات إلى فرص وعملاء محتملين.','Designing and developing modern, fast, and impressive websites that help convert visits into opportunities and potential clients.'),('إدارة الحملات والمحتوى والإعلانات على منصات التواصل لبناء حضور فعّال وتحقيق نتائج قابلة للقياس.','Managing cam